  `drop_target_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `drop_target_id` bigint unsigned NOT NULL,
  `drop_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
